select 
from extract_config

    and status != 'DELETED'

        and (config_name like #{keywordLike}
        or config_code like #{keywordLike}
        or document_type like #{keywordLike})


        and status = #{query.status}


        and department_id = #{query.departmentId}


        and document_type = #{query.documentType}


        and category = #{query.category}


        and sub_category = #{query.subCategory}


        and template_type = #{query.templateType}


order by updated_at desc

select 
from extract_config
where status = 'PUBLISHED'

  and department_id = #{departmentId}


  and category = #{category}


  and sub_category = #{subCategory}


  and template_type = #{templateType}


  and document_type = #{documentType}

order by published_at desc, version desc

select max(version)
from extract_config
where config_code = #{configCode}

